    passed=bool(checks["safe_pool_benchmark_like_count_non_zero"] and checks["selected_benchmark_like_count_non_zero"] and checks["false_safe_projection_rate_delta_improved_vs_support_contract_probe"] and checks["unsafe_overcommit_rate_delta_returned_to_zero_or_improved"] and psr>=0.98)
    return {"passed":bool(passed),"shadow_contract":"diagnostic_probe","proposal_semantics":"diagnostic","reason":"diagnostic shadow passed: late benchmark-like transfer alignment produced real benchmark-like survivors while suppressing cosmetic safe-pool gains" if passed else "diagnostic shadow failed: late benchmark-like transfer alignment did not produce a clean enough benchmark-like transfer path","observability_gain":art["observability_gain"],"activation_analysis_usefulness":art["activation_analysis_usefulness"],"ambiguity_reduction":art["ambiguity_reduction"],"safety_neutrality":art["safety_neutrality"],"later_selection_usefulness":art["later_selection_usefulness"],"diagnostic_conclusions":art["diagnostic_conclusions"],"artifact_path":str(ap)}
